var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하, 역시 실력이 좋으시네요. 서윤 양.","JPN":"ハハ、アオイさん。さすがですね。","ENG":"Hah hah, you're very good, Seo Yoon.","TWN":"哈哈，妳的實力果然非常出色，徐芸小姐。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"언더그라운드에서 꽤나 유명하셨다던 것도 납득이 가는데요?","JPN":"アンダーグラウンドで有名だったのも嘘ではないようですね。","ENG":"There's a reason you were so famous in the Underground.","TWN":"我現在知道妳為什麼在地下世界那麼出名了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"칭찬은 싫어하진 않지만 선배가 말하니까 전혀 칭찬 같이 안 들리네.","JPN":"褒められるのは嫌いじゃないけど、先輩から言われると耳障りね。","ENG":"I like compliments, but that doesn't sound like a compliment, coming from you.","TWN":"雖然我很喜歡被人誇讚，但是由你說出口，總覺得不像是在誇我。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"지금도 본 실력은 숨기고 날 가지고 노는 것 같기도 하고.","JPN":"今も本気を出さずに遊んでるように見えるし。","ENG":"I also think you're hiding your true capabilities and just playing games with me.","TWN":"你現在沒有發揮出你全部的實力吧，總覺得你在耍我。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"설마 그럴 리가 있겠습니까? 절 너무 과대평가 하시나 보네요.","JPN":"まさか、そんなことはありませんよ。あまり僕のことを過大評価しないでください。","ENG":"Absolutely not. You're overestimating me.","TWN":"怎麼可能呢？妳真是高估我了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그리고 본 실력을 숨기는 건 서윤 양도 마찬가지 아니었나요?","JPN":"あと、本気を出していないのはアオイさんも同じではありませんか？","ENG":"Besides, you're also hiding your true capabilities, aren't you?","TWN":"而且隱藏真正實力的，不只是我，還有妳吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"뭐, 이렇게 계속 소란을 피우다간 일이 귀찮아지겠네요.","JPN":"まあ、このまま騒がれてしまったら面倒なことになりそうですし。","ENG":"Well, I can't let you cause any more trouble than you already have.","TWN":"再這樣鬧下去，會越來越麻煩的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그러니 조금만 더 힘을 써 보도록 하죠.","JPN":"少しだけ本気を出させてもらいましょう。","ENG":"So, let me do this just one more time.","TWN":"所以我還是加把勁吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"이런, 갑자기 말수가 줄어드셨네요.","JPN":"おや、口数が減りましたね。","ENG":"Uh-oh, you're not talking anymore.","TWN":"哎呀，怎麼突然話這麼少了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"너무 걱정 마세요. 아픈 건 잠깐이니까요.","JPN":"そんなに心配しなくても大丈夫です。痛みは一瞬ですので。","ENG":"Don't worry. The pain won't last long.","TWN":"不要太擔心，疼一會就好了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"지금이야!","JPN":"今よ！","ENG":"NOW!","TWN":"就是現在！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"음?!","JPN":"……！？","ENG":"Mm?","TWN":"嗯？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이거나 먹어라! 이 사기꾼!","JPN":"これでも食らえ！　ペテン師野郎！","ENG":"Take this, you fraud!","TWN":"接我一招！你這個騙子！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"크윽......! 실비아 양?!","JPN":"くっ……！　シルビアさん！？","ENG":"Ugh! Sylvia?","TWN":"咳嗯……！希爾維亞小姐？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"분명히 날뛰지 못하게 묶어 뒀을 텐데, 어떻게......?","JPN":"動けないように縛っていたのに、どうやって……？","ENG":"I tied you up. How?","TWN":"我明明綁的很緊，怎麼會……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실은 내가 선배 몰래 밧줄을 느슨하게 풀어뒀거든.","JPN":"実は私が先輩に気づかれないよう、縄を緩めておいたの。","ENG":"Actually, I loosened her rope without your knowing,","TWN":"是我趁你不注意，偷偷鬆開了繩子。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"혹시라도 이런 일이 생기면 뒤를 노려서 공격하라고 말이야.","JPN":"こんな事態が起きた場合に、隙を突いて攻撃させるためにね。","ENG":"so that she could swoop in, if something like this were to happen.","TWN":"就是為了以防萬一，好讓她在背後攻擊你。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아니, 그러다가 정말 실비아 씨가 범인이기라도 하면 어쩌시려고요?","JPN":"いや、もしシルビアさんが犯人だったら、どうするつもりなんですか？","ENG":"What? What if Sylvia was the perpetrator?","TWN":"妳就不怕希爾維亞是真凶嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런 건 그때 가서 생각하는 거지. 어차피 내가 손해 볼 일은 없잖아?","JPN":"それはその時よ！　どうせ私が損するわけじゃないし。","ENG":"I was going to cross that bridge when I came to it. I had nothing to lose by helping her at that time.","TWN":"到時候再說囉，反正我也不吃虧不是嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하, 역시 어릴 적부터 사회생활을 시작한 분이라 발상이 아주 창의적이시네요.","JPN":"ハハ、さすが子どもの頃から社会に出ている人は発想が創意的ですね。","ENG":"Hah hah. You're so unconventional, having started working earlier than others your age.","TWN":"哈哈，果然從小身處社會就是不一樣啊，連想法都如此與眾不同。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그 칭찬은 고맙게 받을게.","JPN":"その褒め言葉、ありがたく頂戴するわ。","ENG":"I'll take that as a compliment.","TWN":"就當你是稱讚我了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 이제 순순히 항복하는 건 어때?","JPN":"それじゃ、そろそろ降参したら？","ENG":"Now, why don't you surrender when we ask you nicely?","TWN":"現在你可以乖乖投降了吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"시끄러워! 누가 항복 같은 거 받아준대?","JPN":"イヤよ！　降参だけで終わらすつもりはないわ！","ENG":"Stuff that! I don't want him to surrender.","TWN":"閉嘴！我才不接受你的投降！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"감히 날 범인으로 몰고 누명을 씌웠겠다?","JPN":"よくもアタシを犯人に仕立てて、汚名を着せたわね。","ENG":"You dared frame me for what you did.","TWN":"膽敢污蔑我，說我是兇手？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"2차전 시작이야! 이 굴욕은 100배로 쳐서 갚아주겠어!","JPN":"2回戦、始めるわよ！　この屈辱は100倍にして返してやる！","ENG":"I want a rematch. I'll make you pay one hundredfold for the humiliation you caused me!","TWN":"第二輪現在開始！我受到的屈辱，我會百倍奉還！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"이런, 무서워라.","JPN":"おやおや、怖いですね。","ENG":"Ooooo, scary!","TWN":"這、真是讓人害怕。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"......저도 조금은 긴장해야겠는걸요.","JPN":"……僕も少しだけ気を引き締めた方がよさそうです。","ENG":"I'd better be on guard.","TWN":"……看來我也得緊張一下了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};